    public function test_backupv2()
    {
        set_time_limit(300);

        $dbHost = '127.0.0.1';
        $dbPort = 3306;
        $dbName = 'laraveldb';
        $dbUser = 'pachim';
        $dbPass = 'poZMFbMed?SG220mOJKP';

        $timestamp = Carbon::now()->format('Y-m-d_H-i-s');
        $dir = storage_path('app/backups');

        if (!is_dir($dir)) {
            mkdir($dir, 0777, true);
        }

        $fileName = "backup_cities_{$timestamp}.sql.gz";
        $filePath = "{$dir}/{$fileName}";

        // 🔹 بکاپ فقط جدول cities
        $command = sprintf(
            'mysqldump --user=%s --password=%s --host=%s --port=%s --no-tablespaces %s users | gzip > %s',
            escapeshellarg($dbUser),
            escapeshellarg($dbPass),
            escapeshellarg($dbHost),
            escapeshellarg($dbPort),
            escapeshellarg($dbName),
            escapeshellarg($filePath)
        );

        exec($command, $output, $returnVar);

        if ($returnVar !== 0 || !file_exists($filePath)) {
            return response()->json([
                'status' => 'error',
                'message' => '❌ Database backup failed.'
            ], 500);
        }

        // 🔹 لیست جداول + تعداد رکورد
        $tables = DB::select('SHOW TABLES');
        $tableKey = 'Tables_in_' . $dbName;

        $tableStats = [];

        foreach ($tables as $table) {
            $tableName = $table->$tableKey;
            $tableStats[] = [
                'table' => $tableName,
                'records' => DB::table($tableName)->count(),
            ];
        }

        // 🔹 ارسال فایل به Bale
        $bale = new BaleService();
        $bale->WalletLog($filePath, 'db_backup_' . $timestamp);

//        // 🔹 حذف فایل
        unlink($filePath);

        return response()->json([
            'status' => 'success',
            'message' => '✅ Cities table backup created & sent.',
            'tables' => $tableStats
        ]);
    }
    public function backup_db_structure()
    {
        try {
            $filePath = backupDatabaseStructureOnly();

            $timestamp = Carbon::now()->format('Y-m-d_H-i-s');

            // ارسال به Bale
            $bale = new BaleService();
            $bale->WalletLog($filePath, 'db_structure_' . $timestamp);

            // حذف فایل
            unlink($filePath);

            return response()->json([
                'status' => 'success',
                'message' => '✅ Database structure backup created & sent successfully.'
            ]);

        } catch (\Exception $e) {
            return response()->json([
                'status' => 'error',
                'message' => $e->getMessage()
            ], 500);
        }
    }


